interface TreeNode {
  value: string;
  children?: TreeNode[];
}

const tree: TreeNode = {
  value: "root",
  children: [
    { value: "child1" },
    {
      value: "child2",
      children: [
        { value: "grandchild1" },
        { value: "grandchild2" }
      ]
    }
  ]
};

function printTree(node: TreeNode, indent: string = ""): void {
  console.log(indent + node.value);
  if (node.children) {
    node.children.forEach(child => printTree(child, indent + "  "));
  }
}

printTree(tree);

